$${\rm{DTI =\ }}{{\left( {{{{\rm{AUC\ brain}}} \over {{\rm{AUC\ plasma}}}}} \right)\ {\rm{examined}}\,\,{\rm{formula}}} \over {\left( {{{{\rm{AUC\ brain}}} \over {{\rm{AUC\ plasma}}}}} \right)\ {\rm{oral}}\,\,{\rm{formula}}}}$$
\end{document}
